def main(branches: list = None):
    branches = [b for b in (branches or []) if isinstance(b, list)]
    if not branches:
        return []
    base = branches[0]
    for other in branches[1:]:
        for i in range(min(len(base), len(other))):
            src, dst = other[i], base[i]
            if not isinstance(src, dict) or not isinstance(dst, dict):
                continue
            for k, v in src.items():
                if k == '_errors':
                    continue
                empty = (None, '', [], {})
                if k not in dst or (dst.get(k) in empty and v not in empty):
                    dst[k] = v
            for e in src.get('_errors', []) or []:
                dst.setdefault('_errors', [])
                if e not in dst['_errors']:
                    dst['_errors'].append(e)
    return base

